# Shapes module - concrete implementations
from definitions import IShape, ITransformable, ShapeType, Point

class Rectangle(IShape, ITransformable):
    width: float
    height: float
    origin: Point

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h
        self.origin = Point(0.0, 0.0)

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    @override
    def describe(self) -> str:
        return f"Rectangle {self.width} x {self.height}"

    @override
    def get_type(self) -> ShapeType:
        return ShapeType.RECTANGLE

    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    def get_bounds(self) -> tuple[float, float]:
        return (self.width, self.height)

    def __str__(self) -> str:
        return f"Rectangle({self.width}, {self.height})"

class Circle(IShape, ITransformable):
    radius: float
    center: Point

    def __init__(self, r: float):
        self.radius = r
        self.center = Point(0.0, 0.0)

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def describe(self) -> str:
        return f"Circle with radius {self.radius}"

    @override
    def get_type(self) -> ShapeType:
        return ShapeType.CIRCLE

    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

    def get_bounds(self) -> tuple[float, float]:
        d: float = self.radius * 2.0
        return (d, d)

    def __str__(self) -> str:
        return f"Circle(r={self.radius})"

