# Utilities module - helper types and functions
from definitions import IShape

class Pair:
    first: float
    second: float

    def __init__(self, a: float, b: float):
        self.first = a
        self.second = b

    def sum(self) -> float:
        return self.first + self.second

    def product(self) -> float:
        return self.first * self.second

    def __str__(self) -> str:
        return f"Pair({self.first}, {self.second})"

def process_shape(shape: IShape) -> float:
    return shape.area()

def create_pair(x: float, y: float) -> Pair:
    return Pair(x, y)
